impl fmt::Display for Money {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let symbol = match self.currency {
            Currency::Usd => "$",
            Currency::Eur => "€",
            Currency::Gbp => "£",
        };
        let major = self.amount / 100;
        let minor = self.amount % 100;

        write!(f, "{}{}.{:02}", symbol, major, minor)
    }
}
